import React, { forwardRef } from 'react';
import { Pie } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend
} from 'chart.js';
import ChartDataLabels from 'chartjs-plugin-datalabels';

ChartJS.register(
  ArcElement,
  Tooltip,
  Legend,
  ChartDataLabels
);

const DataInsightsPieChart = forwardRef(({ data }, ref) => {
  if (!Array.isArray(data) || data.length === 0) return null;

  const keys = Object.keys(data[0]);
  const labelKey = keys.find(k => typeof data[0][k] === 'string');
  const valueKey = keys.find(k => typeof data[0][k] === 'number');

  if (!labelKey || !valueKey) return null;

  const grouped = {};
  data.forEach(item => {
    const label = item[labelKey];
    const value = item[valueKey];
    grouped[label] = (grouped[label] || 0) + value;
  });

  const labels = Object.keys(grouped);
  const values = Object.values(grouped).map(v =>
    Number(v.toFixed(2))
  );

  const chartData = {
    labels,
    datasets: [
      {
        data: values,
        backgroundColor: [
          '#6366F1',
          '#22C55E',
          '#F97316',
          '#EF4444',
          '#14B8A6',
          '#0EA5E9',
          '#A855F7'
        ],
        borderColor: '#ffffff',
        borderWidth: 2
      }
    ]
  };

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    cutout: '60%',
    plugins: {
      legend: {
        position: 'top',
        labels: {
          boxWidth: 14,
          padding: 12,
          font: {
            size: 12,
            weight: '500'
          }
        }
      },
      tooltip: {
        backgroundColor: '#1f2937',
        padding: 10,
        cornerRadius: 6,
        callbacks: {
          label: (ctx) => `${ctx.label}: ${ctx.raw.toFixed(2)}%`
        }
      },
      datalabels: {
        color: '#ffffff',
        font: {
          size: 12,
          weight: 'bold'
        },
        formatter: (value) => `${value.toFixed(2)}%`
      }
    }
  };

  return <Pie ref={ref} data={chartData} options={options} />;
});

export default DataInsightsPieChart;
